{
  "experiment_plan": {
    "what_to_compare": "2000-2010年の米国州別四半期パネルにおいて、Castle Doctrine法（Stand Your Ground法）を採用した州の採用前後の変化と、同時期に未採用の州の変化を比較する。主比較は、採用州のイベントスタディ推定値と未採用州の対照トレンド。補助比較として、採用時期の異なる州同士の相対時点比較、および採用前のプレトレンド比較を行う。",
    "what_to_measure": "州×四半期の犯罪率（人口10万人当たり）として、殺人・過失致死、強盗、加重暴行を主要アウトカムとする。補助的に、非致死的暴力の合成指標、対人犯罪比率、採用前トレンド、同時期の州政策指標（警察配置、銃関連政策、治安関連支出など）を測定する。",
    "procedure": "1) 州別にCastle Doctrine法の採用時点を整理し、四半期パネルを作成する。2) 採用州と未採用州を用いてイベントスタディ型の差の差分析を実施し、採用前の係数で平行トレンドを検査する。3) 主要アウトカムごとに、採用後の短期（0-4四半期）、中期（5-12四半期）、長期（13四半期以上）の効果を推定する。4) 同時政策・州内要因を追加した仕様、州固定効果・時点固定効果のみの仕様、採用前トレンド制御を含む仕様を順に比較する。5) Goodman-Bacon型の分解または代替推定（例: cohort-specific/event-study推定）で、staggered adoption下のTWFEの重み問題を点検する。6) 主要仮説ごとに、アウトカム別の符号・有意性・時間パターンを判定する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "採用がなければ、採用州と未採用州のアウトカムは共通トレンドに従う（条件付き平行トレンド）。",
        "if_violated": "採用前係数に系統的な差があり、採用前から採用州のアウトカムが未採用州と異なる傾向を示す場合、因果解釈は弱まり、推定結果は選択バイアスの可能性が高いと判断する。",
      },
      {
        "id": "IA2",
        "description": "法採用時期は、同時点の未観測ショックやアウトカムの急変によって決まっていない（採用タイミングの外生性）。",
        "if_violated": "犯罪増加や治安悪化への反応として法が導入された証拠がある場合、推定された効果は逆因果や政策内生性を含む可能性がある。",
      },
      {
        "id": "IA3",
        "description": "法採用の影響は他州へ大きく波及しない、または波及があっても比較群の構成を実質的に歪めない（SUTVA/干渉の限定）。",
        "if_violated": "隣接州への犯罪移転や政策模倣が強く、対照州が処置の影響を受ける場合、推定効果は過小または過大に歪む。",
      },
      {
        "id": "IA4",
        "description": "アウトカム測定が州間で比較可能であり、法改正後に報告・分類基準が大きく変わらない。",
        "if_violated": "犯罪統計の定義変更や報告慣行の変化が採用時期と一致する場合、見かけの効果が測定誤差に由来する可能性がある。",
      },
      {
        "id": "IA5",
        "description": "同時期の主要な州政策や治安ショックを観測・調整できる、またはそれらが採用時期と強く相関しない。",
        "if_violated": "警察配置、銃政策、刑事司法政策などの同時変化が採用州に集中し、法効果と分離できない場合、H4の交絡仮説が支持される。",
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "採用後に強盗・加重暴行が未採用州比で有意に低下し、その低下が短中期で一貫して観察され、かつ殺人・過失致死では同程度の増加が見られない。",
        "reject_if": "採用後に強盗・加重暴行が増加する、または低下が一時的・不安定で、抑止効果の一貫した証拠がない。",
        "hold_if": "強盗・加重暴行に小さな負の推定値はあるが、有意性・持続性・頑健性が不足し、結論を保留する。",
      },
      {
        "id": "H2",
        "accept_if": "採用後に殺人・過失致死が未採用州比で有意に上昇し、その上昇が時間経過とともに現れるか拡大し、非致死的暴力の変化と独立に確認される。",
        "reject_if": "採用後に殺人・過失致死が上昇せず、または上昇が短期的・不安定で、エスカレーション効果の証拠がない。",
        "hold_if": "殺人・過失致死に正の推定値はあるが、統計的に不明確、あるいは仕様変更で消失する場合。",
      },
      {
        "id": "H3",
        "accept_if": "同一仕様で、強盗・加重暴行は有意に減少し、同時に殺人・過失致死は有意に増加するという符号の分岐が確認される。",
        "reject_if": "非致死的暴力と致死的暴力が同方向に動く、または少なくとも一方が明確な変化を示さない。",
        "hold_if": "アウトカム間で符号の分岐はあるが、いずれも有意性・頑健性が不足し、複合仮説として断定できない。",
      },
      {
        "id": "H4",
        "accept_if": "州固定効果・時点固定効果のみの推定から、採用前トレンド制御および同時政策変数の追加で法効果が大きく減衰または消失し、採用前にも系統的な差が確認される。",
        "reject_if": "採用前トレンドや同時政策を調整しても法効果がほぼ不変で、事前差や同時政策の寄与が確認できない。",
        "hold_if": "調整後に効果が部分的に減衰するが、どの要因が主因か特定できず、交絡の程度を確定できない。",
      },
      {
        "id": "H1_H2_independent",
        "accept_if": "H1の判定は強盗・加重暴行のみで行い、H2の判定は殺人・過失致死のみで行うため、H1が成立してもH2の判定条件を変えず、逆も同様である。",
        "reject_if": "H1の結果をH2の判定に流用する、またはその逆を行い、独立性が損なわれる。",
        "hold_if": "両者の判定が別アウトカムに基づき、相互参照なしで実施される限り、独立性は維持される。",
      },
      {
        "id": "H1_H4_independent",
        "accept_if": "H1は犯罪アウトカムの変化のみで判定し、H4は採用前トレンドと同時政策の寄与のみで判定するため、互いの判定条件を共有しない。",
        "reject_if": "H1のアウトカム変化をH4の交絡判定に組み込む、またはH4の交絡証拠をH1の真偽判定に直接使う。",
        "hold_if": "H1とH4を別々の基準で評価し、片方の結論が他方の判定規則を変更しない場合、独立性は保たれる。",
      },
      {
        "id": "H2_H4_independent",
        "accept_if": "H2は致死的暴力の時間変化のみ、H4は識別上の交絡のみで判定し、判定基準が交差しない。",
        "reject_if": "H2の推定結果をH4の交絡評価に転用する、またはH4の調整後推定をH2のメカニズム判定に混同する。",
        "hold_if": "致死的暴力の増加が見えても、それが法効果か交絡かを別々に評価できる限り、独立に判定可能である。",
      }
    ],
    "analysis_forks": [
      "TWFEイベントスタディを主分析とし、staggered adoptionの負のウェイト問題を確認する分岐",
      "cohort-specific推定またはSun-Abraham型推定に切り替えて、TWFE結果と整合するか確認する分岐",
      "採用前トレンドが不成立の場合は、因果解釈を保留し、H4支持の可能性を優先する分岐",
      "同時政策変数を追加して効果が大きく減衰する場合は、法そのものより交絡要因を重視する分岐",
      "強盗・加重暴行のみ減少し殺人・過失致死が増加する場合は、H3を支持し、H1とH2を部分的に同時採択する分岐",
      "主要アウトカムのいずれも有意でない場合は、検出力不足、測定誤差、または真の効果なしの分岐を検討する",
      "州別の異質性分析として、銃保有率、都市化、南部ダミー、既存の自己防衛法の有無で効果を層別化する分岐"
    ]
  }
}
